/* Sass/Less required for nesting */
/* In vanilla CSS, every rule had to be written flat */
.card { background: #1e293b; }
.card:hover { border-color: #a855f7; }
.card .title { font-weight: 600; }
.card .body { color: #94a3b8; }

startingCSS:
.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0.75rem;
}

.card {
  background: #1e293b;
  border: 2px solid #334155;
  border-radius: 10px;
  padding: 1.25rem;
  cursor: pointer;
  transition: border-color 0.2s;

  /* Add a hover state using & nesting */
  /* &:hover { border-color: #a855f7; } */

  & .title {
    font-weight: 600;
    color: #e2e8f0;
    margin-bottom: 0.4rem;
    font-size: 0.9rem;
  }

  & .body {
    color: #64748b;
    font-size: 0.8rem;
    line-height: 1.5;
  }
}
